// r_main.ts — main renderer module

let r_framecount = 0;
let r_visframecount = 0;
let c_brush_polys = 0;
let c_alias_polys = 0;

class Renderer {
  constructor(private readonly gl: WebGLRenderingContext) {}

  renderView(): void {
    r_framecount++;
    c_brush_polys = 0;
    c_alias_polys = 0;
    this.setupFrame();
    this.markLeaves();
    this.drawWorld();
  }

  private setupFrame(): void {
    r_visframecount++;
  }
}
